//! Image generation command — calls Gemini image generation or falls back
//! to the free Pollinations.ai service. Images are saved under
//! `<app_data>/illustrations/` and the frontend stores the returned path.

use std::fs;
use std::path::PathBuf;

use tauri::{AppHandle, Manager};

use crate::commands::secrets::get_api_key;

fn illustrations_dir(app: &AppHandle) -> Result<PathBuf, String> {
    let base = app
        .path()
        .app_data_dir()
        .map_err(|e| format!("nepodařilo se najít adresář aplikace: {e}"))?;
    let dir = base.join("illustrations");
    fs::create_dir_all(&dir).map_err(|e| format!("nepodařilo se vytvořit adresář ilustrací: {e}"))?;
    Ok(dir)
}

/// Generates an illustration for the given prompt and saves it to disk.
///
/// If `connection_id` is provided and the connection's provider is `gemini`,
/// the command uses the Gemini image-generation API (Imagen). Otherwise it
/// falls back to the free Pollinations.ai service, which requires no API key.
///
/// Returns the absolute path to the saved image file.
#[tauri::command]
pub async fn generate_illustration(
    app: AppHandle,
    connection_id: Option<String>,
    prompt: String,
) -> Result<String, String> {
    let dir = illustrations_dir(&app)?;
    let filename = format!("{}.png", uuid::Uuid::new_v4());
    let dest = dir.join(&filename);

    // Try Gemini image generation when a connection is provided
    let bytes: Vec<u8> = if let Some(ref cid) = connection_id {
        match try_gemini_image(cid, &prompt).await {
            Ok(img_bytes) => img_bytes,
            Err(gemini_err) => {
                // Fall back to Pollinations on any Gemini failure
                eprintln!("Gemini image gen failed, falling back to Pollinations: {gemini_err}");
                pollinations_image(&prompt).await.map_err(|e| e.to_string())?
            }
        }
    } else {
        pollinations_image(&prompt).await.map_err(|e| e.to_string())?
    };

    fs::write(&dest, &bytes)
        .map_err(|e| format!("nepodařilo se uložit ilustraci: {e}"))?;

    Ok(dest.to_string_lossy().to_string())
}

/// Generates an image via Pollinations.ai (free, no API key needed).
/// URL: https://image.pollinations.ai/prompt/{encoded_prompt}?width=512&height=512&nologo=true
async fn pollinations_image(prompt: &str) -> Result<Vec<u8>, reqwest::Error> {
    let encoded = urlencoding(&prompt);
    let url = format!(
        "https://image.pollinations.ai/prompt/{}?width=512&height=512&nologo=true",
        encoded
    );
    let client = reqwest::Client::new();
    let resp = client.get(&url).send().await?;
    resp.bytes().await.map(|b| b.to_vec())
}

/// Tries to generate an image via the Gemini API using Imagen.
/// Uses the keyring-stored API key for the given connection.
async fn try_gemini_image(connection_id: &str, prompt: &str) -> Result<Vec<u8>, String> {
    let api_key = get_api_key(connection_id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    let client = reqwest::Client::new();
    let url = format!(
        "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-exp-image-generation:generateContent"
    );

    let body = serde_json::json!({
        "contents": [{
            "parts": [{
                "text": format!("Generate a high-quality illustration in a dark fantasy RPG style: {prompt}")
            }]
        }],
        "generationConfig": {
            "responseModalities": ["IMAGE", "TEXT"]
        }
    });

    let resp = client
        .post(&url)
        .header("x-goog-api-key", &api_key)
        .json(&body)
        .send()
        .await
        .map_err(|e| format!("HTTP error: {e}"))?;

    let status = resp.status();
    let resp_body: serde_json::Value = resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse Gemini response: {e}"))?;

    if !status.is_success() {
        let msg = resp_body["error"]["message"]
            .as_str()
            .unwrap_or("unknown error");
        return Err(format!("Gemini API error ({status}): {msg}"));
    }

    // Extract inline image data from Gemini's response.
    // Gemini returns base64-encoded images in candidates[].content.parts[]
    // where a part has `inlineData.mimeType` and `inlineData.data`.
    if let Some(parts) = resp_body["candidates"][0]["content"]["parts"].as_array() {
        for part in parts {
            if let Some(data) = part["inlineData"]["data"].as_str() {
                return base64::Engine::decode(
                    &base64::engine::general_purpose::STANDARD,
                    data,
                )
                .map_err(|e| format!("Failed to decode base64 image: {e}"));
            }
        }
    }

    Err("Gemini response did not contain an inline image".to_string())
}

/// Minimal percent-encoding for Pollinations URL — only encodes the
/// characters that would break the URL path.
fn urlencoding(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => out.push(b as char),
            b' ' => out.push_str("%20"),
            _ => {
                out.push('%');
                out.push_str(&format!("{:02X}", b));
            }
        }
    }
    out
}

